// ============================================================
// ESCALATION EMAIL BUILDER — Workflow 3, Node 4
// ============================================================

const data = $json;
const emp = data.employee || {};

// ---- HARD VALIDATION (prevents Bad Request) ----
if (!emp.email) {
  throw new Error("Employee email missing");
}

if (!data.hodEmail) {
  throw new Error("HOD email missing");
}

const allDeals = data.details || data.deals || [];
const max = data.maxDealsPerMsg || 8;

const senderName = data.senderName || 'Averlon System';
const dealListUrl = data.dealListUrl || '#';
const totalDeals = data.totalDeals || allDeals.length;

const shownDeals = allDeals.slice(0, max);
const remainingCount = allDeals.length - shownDeals.length;

function escapeHtml(str = '') {
  return String(str).replace(/[&<>"']/g, s => ({
    '&': '&amp;', '<': '&lt;', '>': '&gt;',
    '"': '&quot;', "'": '&#39;'
  }[s]));
}

function dealRowHtml(deal, index) {
  const days = deal.daysLeft;

  let statusColor = '#0F6E56';
  let statusText  = '';

  if (days < 0) {
    statusColor = '#E24B4A';
    statusText  = `⚠ Overdue by ${Math.abs(days)} day(s)`;
  } else if (days === 0) {
    statusColor = '#BA7517';
    statusText  = '🔴 Due Today';
  } else {
    statusText = `Due in ${days} day(s)`;
  }

  return `
  <tr style="border-bottom: 1px solid #e8e8e8;">
    <td style="padding: 12px 8px; font-size: 14px; color: #2c2c2a; font-weight: 500;">
      ${index + 1}. ${escapeHtml(deal.title || 'Deal')}
    </td>
    <td style="padding: 12px 8px; font-size: 13px; color: #5f5e5a;">
      ${escapeHtml(deal.renewalDateFormatted || 'No date')}
    </td>
    <td style="padding: 12px 8px; font-size: 12px; color: ${statusColor}; font-weight: 600;">
      ${statusText}
    </td>
    <td style="padding: 12px 8px;">
      <a href="${deal.url || '#'}"
         style="background: #A32D2D; color: white; font-size: 12px; padding: 5px 12px; border-radius: 6px; text-decoration: none;">
        View →
      </a>
    </td>
  </tr>`;
}

const dealRowsHtml = shownDeals.map((d, i) => dealRowHtml(d, i)).join('');

const remainingHtml = remainingCount > 0 ? `
  <div style="margin: 16px 0; padding: 12px 16px; background: #FCEBEB; border-radius: 8px; font-size: 14px; color: #A32D2D;">
    And <strong>${remainingCount} more deal(s)</strong> still pending.
    <a href="${dealListUrl}" style="color: #A32D2D; font-weight: 600;">View all →</a>
  </div>` : '';

// ---- EMPLOYEE EMAIL HTML ----
const empEmailHtml = `<!DOCTYPE html><html><head><meta charset="UTF-8"></head>
<body style="margin:0;padding:0;background:#f4f4f0;font-family:-apple-system,BlinkMacSystemFont,'Segoe UI',sans-serif;">
  <div style="max-width:620px;margin:32px auto;background:white;border-radius:12px;overflow:hidden;border:1px solid #d3d1c7;">
    <div style="background:#A32D2D;padding:28px 32px;">
      <div style="font-size:11px;color:#F7C1C1;font-weight:600;letter-spacing:1px;text-transform:uppercase;margin-bottom:6px;">${senderName}</div>
      <h1 style="margin:0;color:white;font-size:22px;font-weight:600;">⚠ Final Escalation Alert</h1>
      <div style="color:#F7C1C1;font-size:13px;margin-top:6px;">6:30 PM · ${data.runDate || ''}</div>
    </div>
    <div style="padding:24px 32px 0;">
      <p style="font-size:15px;color:#2c2c2a;margin:0 0 8px;">Hi <strong>${escapeHtml(emp.name || 'User')}</strong>,</p>
      <p style="font-size:14px;color:#5f5e5a;margin:0 0 8px;">This is your <strong>final escalation</strong> for today. You still have <strong>${totalDeals} unresolved deal(s)</strong>. Your HOD has been notified.</p>
      <p style="font-size:14px;color:#A32D2D;font-weight:500;margin:0 0 20px;">Please update these deals immediately.</p>
    </div>
    <div style="padding:0 32px;">
      <table style="width:100%;border-collapse:collapse;">
        <thead>
          <tr style="background:#f1efe8;">
            <th style="padding:10px 8px;text-align:left;font-size:12px;color:#888780;font-weight:600;">Deal Name</th>
            <th style="padding:10px 8px;text-align:left;font-size:12px;color:#888780;font-weight:600;">Due Date</th>
            <th style="padding:10px 8px;text-align:left;font-size:12px;color:#888780;font-weight:600;">Status</th>
            <th style="padding:10px 8px;text-align:left;font-size:12px;color:#888780;font-weight:600;">Action</th>
          </tr>
        </thead>
        <tbody>${dealRowsHtml}</tbody>
      </table>
    </div>
    ${remainingHtml}
    <div style="padding:24px 32px;border-top:1px solid #e8e8e8;margin-top:16px;">
      <p style="font-size:12px;color:#888780;margin:0;">Automated alert from ${senderName}. Do not reply.</p>
    </div>
  </div>
</body></html>`;

// ---- HOD EMAIL HTML ----
const hodEmailHtml = `<!DOCTYPE html><html><head><meta charset="UTF-8"></head>
<body style="margin:0;padding:0;background:#f4f4f0;font-family:-apple-system,BlinkMacSystemFont,'Segoe UI',sans-serif;">
  <div style="max-width:620px;margin:32px auto;background:white;border-radius:12px;overflow:hidden;border:1px solid #d3d1c7;">
    <div style="background:#633806;padding:28px 32px;">
      <div style="font-size:11px;color:#FAC775;font-weight:600;letter-spacing:1px;text-transform:uppercase;margin-bottom:6px;">${senderName}</div>
      <h1 style="margin:0;color:white;font-size:22px;font-weight:600;">HOD Escalation CC</h1>
      <div style="color:#FAC775;font-size:13px;margin-top:6px;">6:30 PM escalation · ${data.runDate || ''}</div>
    </div>
    <div style="padding:24px 32px 0;">
      <p style="font-size:15px;color:#2c2c2a;margin:0 0 8px;">Hi <strong>${escapeHtml(data.hodName || 'Manager')}</strong>,</p>
      <p style="font-size:14px;color:#5f5e5a;margin:0 0 20px;">Your team member <strong>${escapeHtml(emp.name || 'User')}</strong> (${escapeHtml(emp.email)}) has <strong>${totalDeals} unresolved deal(s)</strong> as of 6:30 PM today. They have been notified separately.</p>
    </div>
    <div style="padding:0 32px;">
      <table style="width:100%;border-collapse:collapse;">
        <thead>
          <tr style="background:#f1efe8;">
            <th style="padding:10px 8px;text-align:left;font-size:12px;color:#888780;font-weight:600;">Deal Name</th>
            <th style="padding:10px 8px;text-align:left;font-size:12px;color:#888780;font-weight:600;">Due Date</th>
            <th style="padding:10px 8px;text-align:left;font-size:12px;color:#888780;font-weight:600;">Status</th>
            <th style="padding:10px 8px;text-align:left;font-size:12px;color:#888780;font-weight:600;">Action</th>
          </tr>
        </thead>
        <tbody>${dealRowsHtml}</tbody>
      </table>
    </div>
    ${remainingHtml}
    <div style="padding:24px 32px;border-top:1px solid #e8e8e8;margin-top:16px;">
      <p style="font-size:12px;color:#888780;margin:0;">Automated alert from ${senderName}. Do not reply.</p>
    </div>
  </div>
</body></html>`;

// ---- PRE-SERIALIZE BOTH EMAIL BODIES (fixes quote-escaping issue) ----
const empEmailBody = JSON.stringify({
  message: {
    subject: `[ESCALATION] ${totalDeals} Unresolved Deals — Action Required`,
    body: {
      contentType: "HTML",
      content: empEmailHtml
    },
    toRecipients: [
      {
        emailAddress: {
          address: emp.email,
          name: emp.name || ''
        }
      }
    ]
  },
  saveToSentItems: true
});

const hodEmailBody = JSON.stringify({
  message: {
    subject: `[HOD ALERT] ${emp.name || 'User'} has ${totalDeals} overdue deal(s) — 6:30 PM Escalation`,
    body: {
      contentType: "HTML",
      content: hodEmailHtml
    },
    toRecipients: [
      {
        emailAddress: {
          address: data.hodEmail,
          name: data.hodName || 'Manager'
        }
      }
    ]
  },
  saveToSentItems: true
});

return [{
  json: {
    ...data,
    escalation: {
      empEmailBody,
      hodEmailBody,
      empEmail: emp.email,
      empName: emp.name,
      hodEmail: data.hodEmail,
      hodName: data.hodName
    }
  }
}];
